def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.25
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-ratio * 12) + 0.15
        elif 0.4 < ratio <= 0.7:
            score = sum((((-1) ** k) * (ratio ** (k + 2))) / (k * 1.2) for k in range(1, 7))
            score = abs(score) + 0.1
        else:
            poly_sum = 0.0
            for k in range(1, 8):
                coeff = 0.1 * ((-1) ** (k + 1))
                poly_sum += coeff * (ratio ** (k + 1))
            score = abs(poly_sum) + 0.2
        neighbors_influence = 0.0
        for offset in range(1, 6):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0 and neighbor_capacity != capacity:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    neighbors_influence += diff_ratio * weight * 0.1
        capacity_factor = np.cbrt(capacity) + 0.1
        adjustment = 0.0
        for j in range(n):
            if j != i and bins[j] > 0:
                dist = abs(i - j)
                cap_diff = abs(capacity - bins[j]) / max(capacity, bins[j])
                adj_term = np.exp(-dist) * cap_diff
                adjustment += adj_term
        adjustment /= (n - 1) if n > 1 else 1
        priority = score + neighbors_influence / capacity_factor + adjustment * 0.05
        if priority < 0:
            priority = 0
        if priority > 1:
            priority = 1
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 10
    max_priority = np.max(priorities)
    if max_priority > 0:
        priorities = priorities / max_priority
    return priorities
